def main() -> None:
    url = os.environ.get("SUPABASE_URL") or os.environ.get("EXPO_PUBLIC_SUPABASE_URL")
    key = os.environ.get("SUPABASE_SERVICE_KEY") or os.environ.get("SUPABASE_KEY") or os.environ.get("SUPABASE_ANON_KEY") or os.environ.get("EXPO_PUBLIC_SUPABASE_ANON_KEY")

    if not url or not key:
        log.error("Missing SUPABASE_URL / SUPABASE_SERVICE_KEY env vars")
        sys.exit(1)

    client = create_client(url, key)

    log.info("Upserting %d electorates...", len(ELECTORATES))
    rows = [{"name": e["name"], "state": e["state"], "postcodes": e["postcodes"], "level": "federal"} for e in ELECTORATES]

    resp = client.table("electorates").upsert(rows, on_conflict="name").execute()
    if hasattr(resp, "error") and resp.error:
        log.error("Upsert failed: %s", resp.error)
        sys.exit(1)

    log.info("Upserted %d electorates OK", len(rows))
    log.info("Re-run ingest_federal_members.py to link members to the new electorates.")


if __name__ == "__main__":
    main()
